-- ============================================================================
-- Quiz Seed: Numbers — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══ Numbers Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 1, 'kids', 1, 'What did God tell Moses to do with all the men of Israel in the wilderness?', 'Count all the men who were old enough to go to war', 'Build a new temple', 'Plant crops for the whole camp', 'Choose twelve new leaders', 'a', 'Numbers 1:2-3 — "Take ye the sum of all the congregation of the children of Israel... from twenty years old and upward, all that are able to go forth to war in Israel."'),
('Numbers', 1, 'kids', 2, 'Which tribe was NOT counted in the military census?', 'The tribe of Levi', 'The tribe of Judah', 'The tribe of Benjamin', 'The tribe of Reuben', 'a', 'Numbers 1:47 — "But the Levites after the tribe of their fathers were not numbered among them."'),
('Numbers', 1, 'kids', 3, 'How many men of Israel were counted in the first census?', 'Six hundred three thousand five hundred and fifty', 'One hundred thousand', 'One million', 'Sixty thousand', 'a', 'Numbers 1:46 — "Even all they that were numbered were six hundred thousand and three thousand and five hundred and fifty."'),
-- Teens
('Numbers', 1, 'teens', 1, 'Where were Moses and Aaron when God commanded the census of Israel?', 'In the wilderness of Sinai, on the first day of the second month of the second year after leaving Egypt', 'In Egypt before the departure', 'At the Jordan River', 'At Mount Carmel', 'a', 'Numbers 1:1 — "And the LORD spake unto Moses in the wilderness of Sinai, in the tabernacle of the congregation, on the first day of the second month, in the second year after they were come out of the land of Egypt."'),
('Numbers', 1, 'teens', 2, 'Why was one prince chosen from each tribe to assist Moses and Aaron with the census?', 'Each man was the head of the house of his fathers, making them the proper tribal representatives for counting their own people', 'They were the wealthiest men in Israel', 'They had the most military experience', 'They were chosen by lot', 'a', 'Numbers 1:4 — "And with you there shall be a man of every tribe; every one head of the house of his fathers."'),
('Numbers', 1, 'teens', 3, 'Which tribe had the largest number of fighting men in the census?', 'Judah, with seventy-four thousand six hundred', 'Reuben, with forty-six thousand five hundred', 'Dan, with sixty-two thousand seven hundred', 'Manasseh, with thirty-two thousand two hundred', 'a', 'Numbers 1:27 — "Those that were numbered of them, even of the tribe of Judah, were threescore and fourteen thousand and six hundred."'),
('Numbers', 1, 'teens', 4, 'What was the specific task assigned to the Levites instead of military service?', 'They were to bear the tabernacle, all its vessels, and minister unto it, camping around it to protect it', 'They were to cook all the food for the camp', 'They were to guard the outer perimeter of the camp', 'They were to teach the children of Israel the law', 'a', 'Numbers 1:50-51 — "But thou shalt appoint the Levites over the tabernacle of testimony... they shall bear the tabernacle, and all the vessels thereof; and they shall minister unto it, and shall encamp round about the tabernacle."'),
('Numbers', 1, 'teens', 5, 'What would happen to any stranger who came near the tabernacle?', 'He would be put to death', 'He would be fined heavily', 'He would be exiled from the camp', 'He would be made a servant', 'a', 'Numbers 1:51 — "And the stranger that cometh nigh shall be put to death."'),
-- Adults
('Numbers', 1, 'adults', 1, 'What is the Hebrew name for the book of Numbers and what does it mean?', 'Bemidbar, meaning "in the wilderness" — describing Israel''s forty-year journey, while the Greek title Arithmoi (Numbers) refers only to the two census events', 'Shemot, meaning "names"', 'Vayikra, meaning "and he called"', 'Devarim, meaning "words"', 'a', 'Numbers 1:1 — "And the LORD spake unto Moses in the wilderness of Sinai." The Hebrew title Bemidbar ("in the wilderness") better captures the book''s narrative of Israel''s wandering than the Greek-derived English title "Numbers."'),
('Numbers', 1, 'adults', 2, 'Which tribe had the smallest number of fighting men, and what later event may explain this?', 'Manasseh with thirty-two thousand two hundred — the smallest of the twelve counted tribes, reflecting that Manasseh was the younger of Joseph''s two sons and received a smaller inheritance', 'Benjamin with thirty-five thousand four hundred', 'Simeon with fifty-nine thousand three hundred', 'Ephraim with forty thousand five hundred', 'a', 'Numbers 1:35 — "Those that were numbered of them, even of the tribe of Manasseh, were thirty and two thousand and two hundred." Manasseh''s small number stands in contrast to later censuses where he surpasses Ephraim, reversing Jacob''s blessing in Genesis 48.'),
('Numbers', 1, 'adults', 3, 'What theological significance does the Levites'' exemption from the census carry?', 'It establishes that God''s ministers are not counted among the military force — their weapons are worship and intercession, and their primary duty is protecting the holy things of God from profanation', 'The Levites were too few to count', 'They were exempt because of age', 'They had already been counted separately', 'a', 'Numbers 1:47-50 — The Levites are set apart not for war but for tabernacle service. This prefigures the NT principle that ministers of the Gospel fight spiritual battles (Ephesians 6:12) rather than carnal ones.'),
('Numbers', 1, 'adults', 4, 'How does the census of 603,550 men connect to the Exodus narrative and Paul''s reference in 1 Corinthians 10?', 'Paul warns Christians using this very generation as an example — they were counted, redeemed, and yet "with many of them God was not well pleased" because of their unbelief and sin in the wilderness', 'Paul never references the wilderness generation', 'The census is unrelated to New Testament theology', 'The number symbolises spiritual maturity', 'a', '1 Corinthians 10:5 — "But with many of them God was not well pleased: for they were overthrown in the wilderness." Paul draws on the census generation to warn against presuming on God''s grace.'),
('Numbers', 1, 'adults', 5, 'What is the significance of the census being taken "on the first day of the second month, in the second year"?', 'It was exactly one month after the tabernacle was erected (Exodus 40:17) — the census organises the newly constituted worshipping community for holy war, linking tabernacle worship to military readiness', 'It was the beginning of the Hebrew New Year', 'It coincided with the Passover feast', 'It marked forty years since the Exodus', 'a', 'Numbers 1:1 and Exodus 40:17 — The tabernacle was completed on the first day of the first month; one month later, God organises the camp for the march to Canaan, showing that proper worship precedes covenant warfare.'),
('Numbers', 1, 'adults', 6, 'What does the death penalty for strangers approaching the tabernacle reveal about God''s holiness?', 'It demonstrates that sinful humanity cannot approach a holy God without proper mediation — only those divinely appointed can stand in God''s presence, pointing forward to Christ as the sole mediator (1 Timothy 2:5)', 'It was merely a political boundary marker', 'It applied only to enemy nations', 'God was indifferent to the regulation', 'a', 'Numbers 1:51 — "The stranger that cometh nigh shall be put to death." This severe boundary underscores God''s unapproachable holiness and foreshadows Hebrews 10:19-22 where Christ''s blood opens a new and living way into the holiest.'),
('Numbers', 1, 'adults', 7, 'Why are two half-tribes of Joseph (Ephraim and Manasseh) counted separately rather than as one tribe of Joseph?', 'Jacob''s adoption of Ephraim and Manasseh as his own sons in Genesis 48 elevated them to full tribal status, and Levi''s exclusion from land inheritance meant Joseph''s double portion preserved the total of twelve land-holding tribes', 'Joseph''s sons quarrelled and split voluntarily', 'Moses made a political decision to divide them', 'The two groups lived in different nations', 'a', 'Genesis 48:5 — "Ephraim and Manasseh, even as Reuben and Simeon, shall be mine." By adopting both sons, Jacob gave Joseph a double inheritance. With Levi serving the tabernacle, this maintains the symbolically complete twelve tribes for land allotment.'),
('Numbers', 1, 'adults', 8, 'What is the typological connection between Israel''s census for holy war and the New Testament concept of spiritual warfare?', 'Just as only the redeemed (those 20 and above) were counted for battle, so Christians — redeemed by Christ''s blood — are enrolled in a spiritual army, equipped not with earthly weapons but with the full armour of God', 'The census has no NT typological significance', 'Only the Old Testament discusses spiritual combat', 'The holy war concept was abolished entirely in the NT', 'a', 'Ephesians 6:13 — "Take unto you the whole armour of God, that ye may be able to withstand in the evil day." Israel''s military census typifies the enrolment of every believer into God''s redeemed army engaged in spiritual warfare.');

-- ═══ Numbers Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 2, 'kids', 1, 'What was placed in the very centre of the Israelite camp?', 'The tabernacle — the tent where God met with His people', 'The king''s palace', 'A large fire', 'A stone altar', 'a', 'Numbers 2:2 — "Every man of the children of Israel shall pitch by his own standard, with the ensign of their father''s house: far off about the tabernacle of the congregation shall they pitch."'),
('Numbers', 2, 'kids', 2, 'Which tribe camped on the east side of the tabernacle and led the march?', 'Judah', 'Reuben', 'Ephraim', 'Dan', 'a', 'Numbers 2:3 — "And on the east side toward the rising of the sun shall they of the standard of the camp of Judah pitch throughout their armies."'),
('Numbers', 2, 'kids', 3, 'How many groups or divisions was the camp of Israel organised into?', 'Four divisions, one on each side of the tabernacle', 'Two divisions, one on each side', 'Twelve separate groups with no divisions', 'Three divisions going north, south, and east', 'a', 'Numbers 2 describes four main divisions: the camp of Judah on the east (v.3), Reuben on the south (v.10), Ephraim on the west (v.18), and Dan on the north (v.25).'),
-- Teens
('Numbers', 2, 'teens', 1, 'Which three tribes formed the division camped on the south side, under Reuben''s standard?', 'Reuben, Simeon, and Gad', 'Issachar, Zebulun, and Judah', 'Benjamin, Manasseh, and Ephraim', 'Asher, Naphtali, and Dan', 'a', 'Numbers 2:10,12,14 — "On the south side shall be the standard of the camp of Reuben... And those which pitch by him shall be the tribe of Simeon... Then the tribe of Gad."'),
('Numbers', 2, 'teens', 2, 'In what order did the four divisional camps set out when Israel marched?', 'Judah first, then Reuben, then Ephraim, then Dan in the rear', 'Dan first, then Ephraim, then Reuben, then Judah last', 'Reuben first, then Judah, then Dan, then Ephraim', 'Levi led the march with the other tribes following', 'a', 'Numbers 2:9,16,24,31 — The marching order was: camp of Judah (east) first, camp of Reuben (south) second, Ephraim (west) third, and Dan (north) in the rear as the rearguard.'),
('Numbers', 2, 'teens', 3, 'Where did the Levites camp in relation to the whole assembly, and what was their order in the march?', 'In the middle, around the tabernacle; they set forward in the midst of the camps as Israel marched', 'On the far outer edge of the camp', 'Ahead of all the other tribes', 'Behind all the other tribes at the very end', 'a', 'Numbers 2:17 — "Then the tabernacle of the congregation shall set forward with the camp of the Levites in the midst of the camp: as they encamp, so shall they set forward, every man in his place by their standards."'),
('Numbers', 2, 'teens', 4, 'Which division camped on the north side of the tabernacle, and what was its total fighting strength?', 'Dan''s division, with one hundred fifty-seven thousand six hundred', 'Reuben''s division, with one hundred fifty-one thousand four hundred and fifty', 'Judah''s division, with one hundred eighty-six thousand four hundred', 'Ephraim''s division, with one hundred eight thousand one hundred', 'a', 'Numbers 2:25,31 — "On the north side shall be the standard of the camp of Dan... All they that were numbered in the camp of Dan were an hundred thousand and fifty and seven thousand and six hundred."'),
('Numbers', 2, 'teens', 5, 'What command did the Israelites obey regarding this camp arrangement?', 'They pitched their tents by their standards and set forward every man in his place according to their families, just as the LORD commanded Moses', 'They chose their own positions freely', 'The tribal elders voted on the arrangement', 'Moses arranged the camp differently from God''s instructions', 'a', 'Numbers 2:34 — "And the children of Israel did according to all that the LORD commanded Moses: so they pitched by their standards, and so they set forward."'),
-- Adults
('Numbers', 2, 'adults', 1, 'What is the theological significance of placing the tabernacle at the exact centre of the Israelite camp?', 'It visually declares that God''s dwelling among His people is the central reality of their national life — all other activity, travel, and community radiates outward from His presence', 'The centre location was purely practical for equal access', 'It was a military defensive strategy', 'It was based on ancient Near Eastern custom without theological meaning', 'a', 'Numbers 2:2 — "Far off about the tabernacle of the congregation shall they pitch." The camp''s layout is a theology in geography — God at the centre, His people surrounding Him, reflecting the eschatological vision of Revelation 21:3 where God dwells with His people.'),
('Numbers', 2, 'adults', 2, 'Why does Judah lead the march, and how does this connect to Jacob''s prophecy in Genesis 49?', 'Jacob prophesied that the sceptre shall not depart from Judah (Genesis 49:10), and Judah''s position as leader of the march anticipates the royal tribe''s pre-eminence, ultimately fulfilled in David and Christ', 'Judah was simply the largest tribe', 'Moses favoured Judah for personal reasons', 'The marching order was chosen by lot', 'a', 'Genesis 49:10 — "The sceptre shall not depart from Judah." Judah''s place at the vanguard foreshadows the regal destiny of the tribe from which David and ultimately Christ descend (Revelation 5:5).'),
('Numbers', 2, 'adults', 3, 'How does the fourfold division of the camp (east/south/west/north) carry cosmic and eschatological symbolism?', 'The four-sided arrangement mirrors the four corners of creation, establishing Israel as a microcosm of God''s universal kingdom — a symbol echoed in Ezekiel''s vision of the four living creatures and John''s vision of the New Jerusalem', 'The arrangement was geographically convenient only', 'There is no symbolic meaning in the four directions', 'The four divisions represent four separate nations', 'a', 'Numbers 2 and Revelation 7:1 — "And after these things I saw four angels standing on the four corners of the earth." Israel''s fourfold camp anticipates the gathering of God''s redeemed from the four corners of the earth.'),
('Numbers', 2, 'adults', 4, 'What ancient Near Eastern parallels exist for the camp arrangement of Numbers 2, and what makes Israel''s version distinct?', 'Egyptian and other ancient armies camped with a royal/divine standard at the centre, but Israel''s arrangement is unique in that God Himself (not merely a divine image) truly dwells at the centre, requiring actual holiness from the surrounding community', 'Israel''s camp arrangement was entirely unprecedented in the ancient world', 'The Egyptians never used camp formations', 'The arrangement was borrowed entirely from Canaanite practice', 'a', 'Numbers 2:2 — Israel''s camp reflects ancient Near Eastern practice of placing the king''s tent at the centre, but Israel''s King is the living God whose actual presence (not a symbol) dwelt in the tabernacle, demanding real holiness from every surrounding tribe.'),
('Numbers', 2, 'adults', 5, 'What is the significance of Dan''s tribe being assigned the rearguard position in the march?', 'Dan is last in Jacob''s birth order of the handmaid sons and received Samson as its most notable member — the rearguard (me''asseph) was an honourable military position protecting the vulnerable, and Dan''s large numbers made it ideal', 'Dan was the weakest tribe and placed last as punishment', 'Dan refused to march with the others', 'Dan was excluded from the main procession', 'a', 'Numbers 2:31 — "All they that were numbered in the camp of Dan were an hundred thousand and fifty and seven thousand and six hundred. They shall go hindmost with their standards." Dan''s massive size (157,600 men) made it ideal for the critical rearguard role.'),
('Numbers', 2, 'adults', 6, 'How does the structured camp arrangement relate to the concept of holy war in the Old Testament?', 'The ordered camp signifies that Israel''s wars are not human campaigns but divinely ordered battles — God''s presence at the centre means He is the true commander, with Israel as His host (tseba''), and all military order flows from divine holiness', 'Holy war was a separate concept with no connection to the camp layout', 'The camp arrangement was purely civilian', 'Military strategy was developed independently of the tabernacle', 'a', 'Numbers 2:9 — "All that were numbered in the camp of Judah were an hundred thousand and fourscore thousand and six thousand and four hundred. These shall first set forth." The Hebrew word tseba'' (host/army) used throughout reflects that Israel''s march is a sacred military procession led by God.'),
('Numbers', 2, 'adults', 7, 'What role does Numbers 2 play in establishing the concept of Israel as a worshipping army rather than merely a military force?', 'The Levites and tabernacle in the centre mean that every military movement is simultaneously a liturgical procession — the army advances from and returns to worship, making warfare itself an act of devotion to God', 'The military and religious functions were kept entirely separate', 'The Levites had no connection to the military camp', 'Worship was only conducted after battles were won', 'a', 'Numbers 2:17 — "The tabernacle of the congregation shall set forward with the camp of the Levites in the midst of the camp." The tabernacle travels with the army, fusing worship and warfare into one holy mission.'),
('Numbers', 2, 'adults', 8, 'How does the total fighting strength of the four divisions compare, and what does the dominance of Judah''s division suggest prophetically?', 'Judah''s eastern division (186,400 men) is the largest, prophetically consistent with Judah''s future royal pre-eminence — from this tribe would come Israel''s greatest kings and ultimately the King of kings', 'All four divisions were of equal strength', 'Reuben''s division was the largest as the firstborn tribe', 'Dan''s division was the largest and most powerful', 'a', 'Numbers 2:9 — "All that were numbered in the camp of Judah were an hundred thousand and fourscore thousand and six thousand and four hundred." Judah''s division of 186,400 is the largest, consistent with the tribe''s prophetic destiny (Genesis 49:8-10).');

-- ═══ Numbers Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 3, 'kids', 1, 'What happened to Aaron''s sons Nadab and Abihu?', 'They died before the LORD when they offered strange fire in the wilderness', 'They became priests and served faithfully', 'They moved away to another tribe', 'They were sent on a special mission', 'a', 'Numbers 3:4 — "And Nadab and Abihu died before the LORD, when they offered strange fire before the LORD, in the wilderness of Sinai, and they had no children."'),
('Numbers', 3, 'kids', 2, 'What were the Levites given to God in place of the firstborn sons of Israel?', 'The Levites were given as a special gift to God instead of all the firstborn males of Israel', 'Gold and silver offerings', 'Land in Canaan', 'Animals from every tribe', 'a', 'Numbers 3:12 — "And I, behold, I have taken the Levites from among the children of Israel instead of all the firstborn that openeth the matrix among the children of Israel."'),
('Numbers', 3, 'kids', 3, 'Who was the leader over all the Levites?', 'Eleazar the son of Aaron the priest', 'Moses'' brother Aaron', 'Caleb the son of Jephunneh', 'Joshua the son of Nun', 'a', 'Numbers 3:32 — "And Eleazar the son of Aaron the priest shall be chief over the chief of the Levites, and have the oversight of them that keep the charge of the sanctuary."'),
-- Teens
('Numbers', 3, 'teens', 1, 'What were the three families of the Levites, and what do their names mean in terms of Israel''s history?', 'Gershon, Kohath, and Merari — the three sons of Levi who went down to Egypt with Jacob and became the ancestral clans of all Levites', 'Kohath, Reuben, and Simeon', 'Aaron, Moses, and Miriam', 'Nadab, Abihu, and Eleazar', 'a', 'Numbers 3:17 — "And these were the sons of Levi by their names; Gershon, and Kohath, and Merari." These three clans divided all Levitical duties among themselves.'),
('Numbers', 3, 'teens', 2, 'Where did the Gershonite families camp and what was their responsibility?', 'They camped behind the tabernacle to the west and were responsible for the curtains, coverings, screens, and cords of the tabernacle', 'They camped on the east and cared for the ark', 'They camped on the south and carried the boards', 'They camped on the north and guarded the outer gate', 'a', 'Numbers 3:23,25 — "The families of the Gershonites shall pitch behind the tabernacle westward... And the charge of the sons of Gershon in the tabernacle of the congregation shall be the tabernacle, and the tent, the covering thereof, and the hanging for the door."'),
('Numbers', 3, 'teens', 3, 'What was the most sacred duty given to the Kohathites?', 'They were to carry the most holy things — the ark, table, candlestick, altars, and vessels of the sanctuary', 'They were to prepare the daily sacrifices', 'They were to teach the law to the people', 'They were to blow the silver trumpets', 'a', 'Numbers 3:31 — "And their charge shall be the ark, and the table, and the candlestick, and the altars, and the vessels of the sanctuary wherewith they minister, and the hanging, and all the service thereof."'),
('Numbers', 3, 'teens', 4, 'How many Levites were counted from one month old and upward?', 'Twenty-two thousand', 'Thirty thousand', 'Twelve thousand', 'Forty-five thousand', 'a', 'Numbers 3:39 — "All that were numbered of the Levites, which Moses and Aaron numbered at the commandment of the LORD, throughout their families, all the males from a month old and upward, were twenty and two thousand."'),
('Numbers', 3, 'teens', 5, 'What was the redemption price for the 273 firstborn Israelites who exceeded the number of Levites?', 'Five shekels apiece, paid to Aaron and his sons', 'Ten shekels apiece, paid to Moses', 'A lamb for each excess firstborn', 'No payment was required', 'a', 'Numbers 3:47 — "Thou shalt even take five shekels apiece by the poll, after the shekel of the sanctuary shalt thou take them." The 273 excess firstborns (22,273 firstborns vs 22,000 Levites) were redeemed by this payment.'),
-- Adults
('Numbers', 3, 'adults', 1, 'What is the theological basis for the Levites being consecrated to God in place of the firstborn?', 'God claimed all firstborn males at the Passover — since He spared Israel''s firstborns by the lamb''s blood, they belonged to Him. The Levites serve as a corporate substitute, embodying the redemptive principle that a substitute takes the place of the condemned', 'The Levites volunteered for temple service', 'God chose the Levites for their superior numbers', 'The arrangement was Moses'' idea, not God''s', 'a', 'Numbers 3:13 — "Because all the firstborn are mine; for on the day that I smote all the firstborn in the land of Egypt I hallowed unto me all the firstborn in Israel, both man and beast: mine shall they be." This substitution principle points forward to Christ, the ultimate substitute.'),
('Numbers', 3, 'adults', 2, 'What does the sin of Nadab and Abihu (mentioned in verse 4) establish as a foundational principle for all Levitical ministry?', 'That worship must be offered precisely as God commands — any deviation from His prescribed order, even with good intentions, constitutes "strange fire" and is rejected by a holy God', 'That God is capricious and punishes worshippers randomly', 'That only the high priest could ever approach God', 'That sacrificial worship was inherently dangerous and discouraged', 'a', 'Numbers 3:4 — "And Nadab and Abihu died before the LORD, when they offered strange fire before the LORD." This event establishes the sobering principle that God is to be worshipped on His terms, not ours — a principle the whole of Levitical law reinforces.'),
('Numbers', 3, 'adults', 3, 'Why are the Levites counted from one month old (different from the other tribes counted from twenty years)?', 'The Levites are not counted for military service but as servants of God — their consecration begins at birth''s earliest measurable stage, reflecting that divine calling precedes any human ability to serve', 'One month was simply a practical age for identification', 'God wanted to count as many Levites as possible', 'The other tribes were also counted from one month in a separate register', 'a', 'Numbers 3:15 — "Number the children of Levi after the house of their fathers, by their families: every male from a month old and upward shalt thou number them." Unlike warriors (20+), Levites are consecrated from infancy, prefiguring the NT truth that consecration to God begins at the new birth, not at human maturity.'),
('Numbers', 3, 'adults', 4, 'What is the significance of Moses camping before the tabernacle on the east with Aaron, a position of special privilege and responsibility?', 'Moses and Aaron camped before the door of the tabernacle eastward — the eastern entrance was the gate of access to God''s presence. Their location declares that prophetic (Moses) and priestly (Aaron) mediation are jointly essential to access God', 'They camped there simply for convenience', 'The east was considered an unimportant direction', 'Moses and Aaron were separated from the Levites as punishment', 'a', 'Numbers 3:38 — "But those that encamp before the tabernacle toward the east, even before the tabernacle of the congregation eastward, shall be Moses, and Aaron and his sons, keeping the charge of the sanctuary." East — the direction of Eden''s gate (Genesis 3:24) — is the place of approach to God.'),
('Numbers', 3, 'adults', 5, 'How does the Merarite clan''s responsibility for the boards, bars, pillars, and sockets relate to the theological concept of God''s foundational word?', 'The structural framework of the tabernacle — carried by Merari — represents the foundational framework of God''s covenant word upon which all worship rests; without the structure there is no tent, just as without God''s word there is no valid worship', 'The Merarites simply had the heaviest burden as punishment', 'Structural duties had no theological significance', 'The boards were purely decorative', 'a', 'Numbers 3:36-37 — "And under the custody and charge of the sons of Merari shall be the boards of the tabernacle, and the bars thereof, and the pillars thereof, and the sockets thereof, and all the vessels thereof... The pillars of the court round about." The structure bears all else — a type of God''s foundational word.'),
('Numbers', 3, 'adults', 6, 'What typological significance does the substitution of Levites for firstborns carry for New Testament theology?', 'Christ is the ultimate firstborn (Colossians 1:15) who was not spared but delivered up for all — reversing the pattern where substitutes were offered for firstborns, as Christ the firstborn Himself became the substitute for all humanity', 'The Levitical substitution has no NT significance', 'The firstborn redemption was only a financial arrangement', 'Levites were superior to firstborns in God''s plan', 'a', 'Romans 8:32 — "He that spared not his own Son, but delivered him up for us all." In Numbers 3, Levites redeem firstborns. In the NT, Christ the firstborn (Colossians 1:15) is Himself not spared, becoming the antitype who redeems all humanity.'),
('Numbers', 3, 'adults', 7, 'What does the precise tally of 22,273 firstborns against 22,000 Levites reveal about God''s method of administration?', 'God''s accounting is exact and equitable — every soul that exceeds the substitutionary provision must be individually redeemed, teaching that no person can shelter under another''s redemption; each must be personally accounted for before God', 'The numbers were approximate and the excess did not matter', 'Moses made an error in counting', 'The 273 excess firstborns were simply ignored', 'a', 'Numbers 3:46 — "And for those that are to be redeemed of the two hundred and three score and thirteen of the firstborn of the children of Israel, which are more than the Levites." Every soul that exceeds the corporate substitute must be individually redeemed — a principle of personal accountability before God.'),
('Numbers', 3, 'adults', 8, 'How does the Kohathites'' responsibility for the most holy things connect to their lineage producing both Moses and Aaron?', 'Kohath was the middle son of Levi, and from him came Amram, whose sons Moses and Aaron became respectively prophet and high priest — God''s sovereign election places the mediators of His covenant in the family responsible for carrying His holiest objects', 'The Kohathites'' duties and Moses'' lineage are unrelated', 'Moses was from the tribe of Judah', 'The Kohathites were chosen because they were the weakest', 'a', 'Numbers 3:27,29 — "And of Kohath was the family of the Amramites... and the families of the Kohathites shall pitch on the side of the tabernacle southward." Amram was a Kohathite (Exodus 6:18,20), making Moses and Aaron members of the very clan tasked with the ark — the ultimate covenant object.');

-- ═══ Numbers Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 4, 'kids', 1, 'What was the age range for active Levitical service carrying the tabernacle?', 'From thirty years old up to fifty years old', 'From twenty years old up to sixty', 'From twelve years old up to forty', 'From eighteen years old up to sixty-five', 'a', 'Numbers 4:3 — "From thirty years old and upward even until fifty years old, all that enter into the host, to do the work in the tabernacle of the congregation."'),
('Numbers', 4, 'kids', 2, 'What did Aaron and his sons do to the holy things before the Kohathites could carry them?', 'They covered all the holy things with cloths and badgers'' skins so the Kohathites could carry them without seeing them', 'They polished them with oil', 'They placed them outside the camp', 'They packed them in clay pots', 'a', 'Numbers 4:5-6 — "And when the camp setteth forward, Aaron shall come, and his sons, and they shall take down the covering vail, and cover the ark of testimony with it: And shall put thereon the covering of badgers'' skins, and shall spread over it a cloth wholly of blue."'),
('Numbers', 4, 'kids', 3, 'What would happen to any Kohathite who touched or looked at the holy things without covering?', 'They would die', 'They would be put out of the camp', 'They would lose their priestly duties', 'They would owe a fine', 'a', 'Numbers 4:15 — "But they shall not touch any holy thing, lest they die." And Numbers 4:20 — "But they shall not go in to see when the holy things are covered, lest they die."'),
-- Teens
('Numbers', 4, 'teens', 1, 'What specific coverings were placed over the ark of the covenant when breaking camp, in the correct order?', 'First the veil of the covering, then badgers'' skins over that, then a cloth wholly of blue, then the staves inserted', 'Blue cloth first, then the veil, then red cloth', 'The ark was carried uncovered but on poles', 'A single white linen cloth covered everything', 'a', 'Numbers 4:5-6 — Aaron and his sons first covered the ark with the veil, then with badgers'' skins, then with a blue cloth, and inserted the carrying poles (staves).'),
('Numbers', 4, 'teens', 2, 'What did Eleazar son of Aaron personally carry as his oversight responsibility?', 'The oil for the light, the sweet incense, the daily meat offering, the anointing oil, and oversight of all the tabernacle and all that therein is', 'The ark of the testimony alone', 'The silver trumpets', 'The offerings from the princes', 'a', 'Numbers 4:16 — "And to the office of Eleazar the son of Aaron the priest pertaineth the oil for the light, and the sweet incense, and the daily meat offering, and the anointing oil, and the oversight of all the tabernacle, and of all that therein is, in the sanctuary, and in the vessels thereof."'),
('Numbers', 4, 'teens', 3, 'What did the Gershonites carry in the Levitical march?', 'The curtains of the tabernacle, the coverings, the hanging for the door, the hangings of the court, and all the cords', 'The boards, bars, and pillars', 'The ark and the mercy seat', 'The bronze altar and its tools', 'a', 'Numbers 4:25 — "And they shall bear the curtains of the tabernacle, and the tabernacle of the congregation, his covering, and the covering of the badgers'' skins that is above upon it, and the hanging for the door of the tabernacle of the congregation."'),
('Numbers', 4, 'teens', 4, 'Who directed the Gershonites in all their duties, and what does this reveal about oversight in worship?', 'Ithamar the son of Aaron the priest directed them — showing that priestly oversight was required for all Levitical service, not just the most sacred tasks', 'Moses personally directed every Levitical family himself', 'The Gershonites organised their own work without priestly oversight', 'Eleazar directed both Gershonites and Merarites', 'a', 'Numbers 4:28 — "This is the service of the families of the sons of Gershon in the tabernacle of the congregation: and their charge shall be under the hand of Ithamar the son of Aaron the priest."'),
('Numbers', 4, 'teens', 5, 'How many Kohathites were numbered for active service (ages 30-50)?', 'Two thousand seven hundred and fifty', 'Eight thousand five hundred and eighty', 'Three thousand two hundred and thirty', 'Two thousand six hundred and thirty', 'a', 'Numbers 4:36 — "And those that were numbered of them by their families were two thousand seven hundred and fifty."'),
-- Adults
('Numbers', 4, 'adults', 1, 'Why was the minimum age for Levitical service set at thirty years, and how does this connect to Jesus'' ministry?', 'Thirty years represented mature judgment and full physical strength for the demanding service — Jesus Himself began His public ministry "about thirty years of age" (Luke 3:23), following this pattern of mature consecrated service', 'Thirty was simply the age when men finished school in Israel', 'The age requirement was arbitrary', 'The Levites had to be thirty to receive full pay', 'a', 'Luke 3:23 — "And Jesus himself began to be about thirty years of age." The Levitical minimum of thirty (Numbers 4:3) and David''s age when he became king (2 Samuel 5:4) established thirty as the age of mature, authoritative service — a pattern Jesus fulfils.'),
('Numbers', 4, 'adults', 2, 'What theological principle is embodied in the multiple layers of covering placed over the ark before transportation?', 'The graduated coverings (veil, badgers'' skins, blue cloth) communicate that God''s unapproachable holiness must be progressively mediated — no one comes to the Holy of Holies directly, typifying Christ as the one through whom alone we approach God', 'The coverings were purely practical waterproofing', 'The layers had no theological meaning', 'The coverings were to protect the craftsmen''s work from weather', 'a', 'Numbers 4:5-6 — The ark''s multiple coverings prefigure Hebrews 10:20 — "through the veil, that is to say, his flesh" — Christ''s incarnation as the veil through which we access the presence of God.'),
('Numbers', 4, 'adults', 3, 'Why were the Kohathites forbidden even to look at the holy things, on pain of death, and what does this teach about the nature of holiness?', 'Holiness is not simply a moral category but an ontological one — the presence of God is literally lethal to sinful humanity, and the elaborate coverings are an act of divine mercy shielding people from what would destroy them', 'The prohibition was a test of obedience rather than a real danger', 'God was concerned about theft', 'Looking was forbidden for political reasons, not spiritual ones', 'a', 'Numbers 4:20 — "They shall not go in to see when the holy things are covered, lest they die." This echoes Exodus 33:20 ("no man shall see me, and live") — God''s holiness is inherently dangerous to fallen humanity, making mediation and covering an act of grace.'),
('Numbers', 4, 'adults', 4, 'What is the significance of the blue cloth covering the table of shewbread and other instruments?', 'Blue (tekhelet) is the colour of heaven and divine transcendence in Scripture — covering earthly instruments with heavenly blue declares that these objects belong not to the earthly realm but to the heavenly realm of God''s service', 'Blue was simply the cheapest dye available', 'Blue was chosen to camouflage the objects in the sky', 'The colour had no symbolic significance', 'a', 'Numbers 4:7-9 — Blue coverings are specified for the table, candlestick, golden altar, and instruments. The same tekhelet blue appears in the high priest''s garments (Exodus 28:31) and the tzitzit fringes (Numbers 15:38), consistently representing divine calling and heavenly origin.'),
('Numbers', 4, 'adults', 5, 'How does the division of labour between Kohathites, Gershonites, and Merarites reflect God''s ordering of worship?', 'God assigns specific roles so that every part of worship is covered with intentionality — no one does everything, everyone does something, and the whole depends on each fulfilling their assigned calling under priestly authority', 'The division was based on family seniority alone', 'The different families competed for the best roles', 'The arrangement was Moses'' invention without divine sanction', 'a', 'Numbers 4:49 — "According to the commandment of the LORD they were numbered by the hand of Moses, every one according to his service, and according to his burden." The ordered division of labour in the tabernacle typifies 1 Corinthians 12:18 — God sets every member in the body as it pleases Him.'),
('Numbers', 4, 'adults', 6, 'What is the theological importance of Eleazar''s personal oversight responsibility as listed in verse 16?', 'Eleazar oversees the oil, incense, daily offering, and anointing oil — the elements of light, prayer, sustenance, and consecration — symbolising that the future high priest must personally ensure that every dimension of the people''s approach to God is maintained', 'Eleazar''s list was administrative only, with no theological depth', 'His oversight was temporary until Aaron recovered', 'The items listed were low-priority leftovers', 'a', 'Numbers 4:16 — "To the office of Eleazar... pertaineth the oil for the light, and the sweet incense, and the daily meat offering, and the anointing oil." These elements represent the totality of Israel''s communion with God: illumination, prayer, daily provision, and the consecrating Spirit — all under priestly care.'),
('Numbers', 4, 'adults', 7, 'How does the retirement age of fifty for Levitical service balance spiritual principle with human limitation?', 'God acknowledges the physical decline of aging by setting a retirement age — honoring the dignity of completed service while preventing exhausted service that would compromise the sanctuary''s care; it reflects God''s knowledge of human frailty', 'Fifty was chosen arbitrarily', 'Levites over fifty were considered spiritually unfit', 'The retirement age was later abolished in the New Testament', 'a', 'Numbers 4:3 — "From thirty years old and upward even until fifty years old, all that enter into the host." God''s design accommodates human physical limits — a mercy, not a condemnation. Even after fifty, Numbers 8:25-26 states retired Levites could assist their brethren, reflecting honoured emeritus service.'),
('Numbers', 4, 'adults', 8, 'What is the total number of all Levites numbered for active service, and what does this represent in the context of the whole camp?', 'Eight thousand five hundred and eighty — representing the dedicated corps of God''s servants maintaining His house within the much larger community of 603,550 warriors, showing that the worshipping core is always a consecrated minority within the broader covenant community', 'Twelve thousand, one for each tribe', 'Twenty-two thousand, same as the full Levitical census', 'Three thousand three hundred', 'a', 'Numbers 4:48 — "Even those that were numbered of them, after their families, were eight thousand and five hundred and fourscore." Of 22,000 Levites, only 8,580 (ages 30-50) were in active tabernacle service — a faithful minority maintaining the worship of the entire nation.');

-- ═══ Numbers Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 5, 'kids', 1, 'Who were to be put out of the camp to keep it clean and holy?', 'Anyone who was leprous, had an issue, or was unclean by touching a dead person', 'Only people who had sinned against Moses', 'Anyone who was too old to work', 'Only people from foreign nations', 'a', 'Numbers 5:2-3 — "Command the children of Israel, that they put out of the camp every leper, and every one that hath an issue, and whosoever is defiled by the dead: Both male and female shall ye put out."'),
('Numbers', 5, 'kids', 2, 'If someone wronged another person, what did God say they should do?', 'Confess their sin and make full restitution by adding a fifth more to what they owed', 'Only say sorry without giving anything back', 'Pay back exactly half of what was taken', 'Bring an animal sacrifice and nothing more', 'a', 'Numbers 5:7 — "Then they shall confess their sin which they have done: and he shall recompense his trespass with the principal thereof, and add unto it the fifth part thereof, and give it unto him against whom he hath trespassed."'),
('Numbers', 5, 'kids', 3, 'What was the bitter water used for in this chapter?', 'To test whether a woman had been unfaithful to her husband', 'To punish soldiers who lost battles', 'To test whether food was poisoned', 'To cleanse the tabernacle of uncleanness', 'a', 'Numbers 5:17-18 — The priest used "bitter water that causeth the curse" as part of the jealousy test to determine whether a wife had been unfaithful to her husband.'),
-- Teens
('Numbers', 5, 'teens', 1, 'Why was it necessary to put unclean persons outside the camp, according to the text''s explicit reason?', 'So they would not defile the camp where God dwelt among His people — holiness of the community was inseparable from God''s presence', 'Because they were contagious and a public health risk only', 'Because they had broken the Mosaic law deliberately', 'Because they refused to work', 'a', 'Numbers 5:3 — "Both male and female shall ye put out, without the camp shall ye put them; that they defile not their camps, in the midst whereof I dwell."'),
('Numbers', 5, 'teens', 2, 'What happened to restitution when the wronged person had no near kinsman to receive it?', 'The restitution was given to the LORD for the priest, in addition to the ram of atonement by which the trespass was made', 'The money was kept by the guilty person', 'It was given to the poor of the congregation', 'Moses held it in trust until a kinsman appeared', 'a', 'Numbers 5:8 — "But if the man have no kinsman to recompense the trespass unto, let the trespass be recompensed unto the LORD, even to the priest; beside the ram of the atonement, whereby an atonement shall be made for him."'),
('Numbers', 5, 'teens', 3, 'What ingredients made up the "bitter water" used in the jealousy ordeal?', 'Holy water from the tabernacle vessel, dust from the tabernacle floor, and the ink washed from the written curses', 'Salt water and vinegar from the priest''s supply', 'Water from the Nile mixed with bitter herbs', 'Spring water and the blood of a dove', 'a', 'Numbers 5:17,23-24 — The priest took holy water in an earthen vessel, put in dust from the tabernacle floor (v.17), then wrote the curses and washed them into the water for the woman to drink (vv.23-24).'),
('Numbers', 5, 'teens', 4, 'What was the result for the woman if she was guilty versus if she was innocent in the jealousy trial?', 'If guilty, her belly would swell and her thigh rot and she would be a curse among her people; if innocent, she would be free and would conceive seed', 'If guilty, she was stoned immediately; if innocent, she was freed without consequences', 'The bitter water had the same effect regardless of guilt', 'If guilty, she was exiled; if innocent, she paid a fine', 'a', 'Numbers 5:27-28 — "If she be defiled... the water that causeth the curse shall enter into her, and become bitter, and her belly shall swell, and her thigh shall rot... And if the woman be not defiled, but be clean; then she shall be free, and shall conceive seed."'),
('Numbers', 5, 'teens', 5, 'What offering did the husband bring on behalf of his wife for the jealousy trial, and what did it lack that other offerings had?', 'One tenth part of an ephah of barley meal — an offering of jealousy without oil and without frankincense', 'A lamb without blemish with oil and salt', 'Fine wheat flour with frankincense', 'Two turtle-doves with oil', 'a', 'Numbers 5:15 — "Then shall he bring her offering for her, the tenth part of an ephah of barley meal; he shall pour no oil upon it, nor put frankincense thereon; for it is an offering of jealousy, an offering of memorial, bringing iniquity to remembrance."'),
-- Adults
('Numbers', 5, 'adults', 1, 'What does the expulsion of the unclean from the camp communicate about the relationship between God''s presence and human sin?', 'God''s holy presence cannot coexist with ritual impurity — the camp must reflect the character of the One who dwells in it. This spatial holiness is not merely ceremonial but teaches the moral truth that sin separates from God', 'The expulsion was a health measure with no theological meaning', 'Only moral sin, not ritual uncleanness, concerned God', 'God tolerated uncleanness as long as it was unintentional', 'a', 'Numbers 5:3 — "That they defile not their camps, in the midst whereof I dwell." The logic is explicit: God''s dwelling presence demands communal holiness. Isaiah 59:2 echoes this — "your iniquities have separated between you and your God."'),
('Numbers', 5, 'adults', 2, 'How does the restitution law of Numbers 5:5-8 integrate the vertical (toward God) and horizontal (toward neighbour) dimensions of sin?', 'Every sin against a neighbour is simultaneously a trespass against God (v.6) — requiring both the guilt offering (atonement toward God) and full restitution plus a fifth (restoration toward the wronged party), reflecting that love of God and love of neighbour are inseparable', 'The law treated sins against God and neighbour as completely separate categories', 'Only the sacrifice to God was required; restitution was optional', 'The horizontal dimension of sin was unimportant in Numbers', 'a', 'Numbers 5:6-7 — "When a man or woman shall commit any sin that men commit, to do a trespass against the LORD, and that person be guilty; Then they shall confess their sin." Sinning against a neighbour is declared to be trespassing against the LORD — a profound moral theology anticipating 1 John 4:20.'),
('Numbers', 5, 'adults', 3, 'What does the jealousy ordeal (sotah) reveal about God''s role as the ultimate judge in matters that human courts cannot adjudicate?', 'When human evidence is insufficient to establish guilt or innocence, God Himself acts as judge through the ordeal — the ritual submits the hidden truth to divine omniscience, affirming that no secret sin escapes God''s knowledge', 'The ordeal was a crude superstition with no real divine involvement', 'God never intervened in marital disputes', 'The ordeal was designed to always condemn the accused woman', 'a', 'Numbers 5:21 — "The LORD make thee a curse and an oath among thy people, when the LORD doth make thy thigh to rot, and thy belly to swell." The ritual acknowledges that only God can penetrate the secrecy of the human heart (Hebrews 4:13 — "all things are naked and opened unto the eyes of him with whom we have to do").'),
('Numbers', 5, 'adults', 4, 'How does the use of dust from the tabernacle floor in the bitter water carry symbolic significance?', 'The dust from God''s dwelling place is incorporated into the trial water — meaning God''s very presence (symbolised by the sanctuary) is invoked into the ordeal, making the judgment inescapably divine rather than merely priestly', 'The dust was a random ingredient with no significance', 'The dust served only as a physical agent in the reaction', 'Tabernacle dust was considered medically curative', 'a', 'Numbers 5:17 — "And the priest shall take holy water in an earthen vessel; and of the dust that is in the floor of the tabernacle the priest shall take, and put it into the water." The dust of God''s house carries the weight of His presence into the test — the sanctuary dust becomes the instrument of divine verdict.'),
('Numbers', 5, 'adults', 5, 'What is the typological significance of the barley meal offering lacking oil and frankincense?', 'Oil represents the Holy Spirit and gladness; frankincense represents pure, acceptable prayer. Their absence from the jealousy offering signals that this is not a joyful communion offering but a solemn bringing of potential sin to divine scrutiny — a "memorial of iniquity" rather than a fragrant offering of fellowship', 'The omission was accidental in the original text', 'Oil and frankincense were simply too expensive for this occasion', 'The ingredients were omitted because the woman might be innocent', 'a', 'Numbers 5:15 — "He shall pour no oil upon it, nor put frankincense thereon; for it is an offering of jealousy, an offering of memorial, bringing iniquity to remembrance." Contrast with Leviticus 2:1 where the standard grain offering includes both oil and frankincense as symbols of blessing.'),
('Numbers', 5, 'adults', 6, 'How does the sotah ritual protect the accused woman as well as enforce marital faithfulness?', 'The ritual provides a legal mechanism for an innocent woman to be exonerated publicly by divine verdict — protecting her from mob violence or arbitrary punishment based on a husband''s jealousy without evidence', 'The ritual was biased against women with no protective function', 'The ritual was designed purely to punish guilty women', 'Women were always found guilty by the ritual', 'a', 'Numbers 5:28 — "If the woman be not defiled, but be clean; then she shall be free, and shall conceive seed." The ritual''s explicit provision for innocence protects the woman from unsubstantiated accusations — a significant legal protection in the ancient world.'),
('Numbers', 5, 'adults', 7, 'What does the phrase "the husband shall be free from iniquity" (verse 31) reveal about the law''s concern for marital justice?', 'The text explicitly clears the suspecting husband of wrongdoing if he follows the proper procedure — the law provides a legitimate, God-ordained channel for jealousy so that it does not fester into private vengeance or public dishonour', 'The phrase means the husband bears no responsibility for the marriage', 'It indicates the husband was always innocent regardless of circumstances', 'The phrase applies only to cases where the wife was guilty', 'a', 'Numbers 5:31 — "Then shall the man be guiltless from iniquity, and this woman shall bear her iniquity." The law channelled legitimate marital jealousy into a divine ordeal rather than human vengeance, providing a framework of justice for both parties.'),
('Numbers', 5, 'adults', 8, 'How does the communal dimension of Numbers 5 (unclean expelled, restitution laws, marital faithfulness) contribute to the theology of Israel as a holy nation?', 'All three laws guard the integrity of God''s covenant community — physical purity, economic justice, and sexual faithfulness are interlocking pillars of a holy society that reflects God''s own character, making Israel''s social order itself a form of witness to the nations', 'The three sections of chapter 5 are unrelated legal fragments', 'Holiness in Numbers 5 is purely ceremonial with no social dimension', 'The communal laws applied only to priests, not ordinary Israelites', 'a', 'Leviticus 19:2 — "Ye shall be holy: for I the LORD your God am holy." Numbers 5 works out what holiness looks like in community: clean bodies, honest commerce, and faithful marriage — all reflecting God''s own purity, justice, and faithfulness.');

-- ═══ Numbers Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 6, 'kids', 1, 'What could a Nazirite not drink or eat during their vow?', 'No wine, no strong drink, no vinegar, and no grapes or raisins — nothing from the vine', 'No meat or fish of any kind', 'No bread or grain', 'No water from the river', 'a', 'Numbers 6:3-4 — "He shall separate himself from wine and strong drink... he shall eat nothing that is made of the vine tree, from the kernels even to the husk."'),
('Numbers', 6, 'kids', 2, 'What could a Nazirite not cut during the days of their special vow to God?', 'Their hair — no razor could come upon their head', 'Their fingernails', 'Their beard only', 'Their clothing', 'a', 'Numbers 6:5 — "All the days of the vow of his separation there shall no rasor come upon his head: until the days be fulfilled, in the which he separateth himself unto the LORD, he shall be holy, and shall let the locks of the hair of his head grow."'),
('Numbers', 6, 'kids', 3, 'What is the beautiful blessing that God told Aaron to speak over the children of Israel?', '"The LORD bless thee, and keep thee: The LORD make his face shine upon thee, and be gracious unto thee: The LORD lift up his countenance upon thee, and give thee peace."', '"May the LORD give you land and gold and many children."', '"Peace be with you and your household for ever."', '"The LORD is your shepherd and you shall not want."', 'a', 'Numbers 6:24-26 — "The LORD bless thee, and keep thee: The LORD make his face shine upon thee, and be gracious unto thee: The LORD lift up his countenance upon thee, and give thee peace."'),
-- Teens
('Numbers', 6, 'teens', 1, 'What happened if a Nazirite accidentally came near a dead body during their vow?', 'Their head was defiled and they had to shave their head, offer two turtledoves and a lamb for atonement, and begin the days of their vow again from the start', 'Their vow was automatically cancelled with no penalty', 'They were put out of the camp permanently', 'They had to offer only one burnt offering', 'a', 'Numbers 6:9-11 — "And if any man die very suddenly by him, and he hath defiled the head of his consecration; then he shall shave his head in the day of his cleansing... and the priest shall make an atonement for him... and he shall hallow his head that same day."'),
('Numbers', 6, 'teens', 2, 'What offerings were presented at the completion of a Nazirite vow?', 'A burnt offering, a sin offering, a peace offering, a basket of unleavened bread, meat offerings, drink offerings, and the wave offering', 'Only a burnt offering and a sin offering', 'Just the wave offering of the hair', 'Seven lambs without blemish', 'a', 'Numbers 6:14-15 — "And he shall offer his offering unto the LORD, one he lamb of the first year without blemish for a burnt offering, and one ewe lamb of the first year without blemish for a sin offering, and one ram without blemish for peace offerings, and a basket of unleavened bread."'),
('Numbers', 6, 'teens', 3, 'What happened to the Nazirite''s hair at the completion of the vow?', 'The Nazirite shaved their consecrated head at the door of the tabernacle and put the hair in the fire under the peace offering', 'The hair was buried outside the camp', 'The hair was given to the priest to keep', 'The Nazirite kept their hair and never cut it again', 'a', 'Numbers 6:18 — "And the Nazarite shall shave the head of his separation at the door of the tabernacle of the congregation, and shall take the hair of the head of his separation, and put it in the fire which is under the sacrifice of the peace offerings."'),
('Numbers', 6, 'teens', 4, 'What three prohibitions defined the Nazirite''s separation in descending order of contact with impurity?', 'No fruit of the vine (consuming), no razor on the head (personal dedication), and no going near a dead body (avoiding ultimate defilement)', 'No speaking to Gentiles, no touching iron, no working on Sabbath', 'No wearing of coloured clothing, no travel outside the camp, no contact with women', 'No eating of meat, no sleeping outside, no contact with Levites', 'a', 'Numbers 6:2-7 — The three marks of separation are: abstinence from wine/grapes (v.3-4), not cutting hair (v.5), and not going near a dead body, even for parents (v.6-7). These three cover inward sustenance, outward appearance, and proximity to death.'),
('Numbers', 6, 'teens', 5, 'What does the final statement "And I will put my name upon the children of Israel; and I will bless them" (verse 27) reveal about the Aaronic blessing?', 'The blessing is not merely priestly words but a divine act — when the priests pronounced it, God Himself placed His name upon Israel, making the blessing inseparably linked to His own identity and authority', 'The blessing was merely a traditional Jewish greeting', 'The priests had power to bless independently of God', 'The blessing applied only to the Levites who heard it', 'a', 'Numbers 6:27 — "And they shall put my name upon the children of Israel; and I will bless them." The Aaronic blessing is God''s own name being placed on His people — the priestly words are the vehicle; the divine Person is the source of all blessing.'),
-- Adults
('Numbers', 6, 'adults', 1, 'What is the etymology and theological significance of the word "Nazirite" (Nazir)?', 'Nazir comes from the Hebrew root nazar, meaning "to consecrate, to separate, to dedicate" — signifying a person set apart for God by a voluntary vow, prefiguring the total consecration of Christ who was "holy, harmless, undefiled, separate from sinners"', 'Nazir means "one who is strong"', 'The word derives from a place name near Sinai', 'Nazir means "one who is silent before God"', 'a', 'Numbers 6:2 — "When either man or woman shall separate themselves to vow a vow of a Nazirite, to separate themselves unto the LORD." The root nazar appears in Hebrews 7:26 — Christ fulfils the Nazirite ideal of complete consecration to God.'),
('Numbers', 6, 'adults', 2, 'How does Samson serve as a theological commentary on the Nazirite vow by both embodying and violating it?', 'Samson was a Nazirite from birth (Judges 13:5) yet violated all three marks — he touched a dead lion (Judges 14:9), attended a wine feast (Judges 14:10), and allowed his hair to be cut (Judges 16:19) — illustrating that outward consecration without inward holiness produces spiritual ruin', 'Samson perfectly fulfilled the Nazirite vow throughout his life', 'Samson''s violations were permitted exceptions to the vow', 'The Nazirite vow and Samson''s story are unrelated', 'a', 'Judges 16:17 — "There hath not come a rasor upon mine head; for I have been a Nazarite unto God from my mother''s womb." Samson''s story is a tragic commentary on Numbers 6 — the form of consecration without its substance leads to shame and defeat.'),
('Numbers', 6, 'adults', 3, 'What does the prohibition against going near a dead body — even for one''s own parents — reveal about the Nazirite''s ultimate loyalty?', 'It demonstrates that consecration to God supersedes even the most sacred natural duties — the Nazirite''s primary relationship is with the living God, not with family bonds, prefiguring Jesus'' statement that following Him takes precedence over burying one''s father (Matthew 8:22)', 'The prohibition was a superstition about death being contagious', 'It showed the Nazirite was exempt from family obligations permanently', 'The rule applied only when the death was of a Gentile', 'a', 'Numbers 6:7 — "He shall not make himself unclean for his father, or for his mother, for his brother, or for his sister, when they die: because the consecration of his God is upon his head." Matthew 8:22 — "Follow me; and let the dead bury their dead" — Jesus echoes this radical prioritising of divine calling over natural ties.'),
('Numbers', 6, 'adults', 4, 'How does the tripartite structure of the Aaronic blessing (bless/keep; shine/gracious; lift up/peace) reflect a progressive deepening of divine grace?', 'The three lines move from protection (bless and keep), to intimate relationship (face shine and graciousness), to shalom — God''s total well-being. Each line intensifies the closeness of God''s engagement, culminating in the gift of His peace, which surpasses understanding', 'The three lines are simple repetitions with identical meaning', 'The blessing has only one theological emphasis: material prosperity', 'The structure is poetic convention with no theological progression', 'a', 'Numbers 6:24-26 — Three stanzas: (1) material blessing and protection, (2) divine favour and grace, (3) God''s full attention and shalom. Philippians 4:7 — "the peace of God, which passeth all understanding" — echoes the culminating gift of the Aaronic blessing.'),
('Numbers', 6, 'adults', 5, 'What is the significance of the vine as the specific source of all Nazirite dietary prohibition, rather than other foods?', 'The vine represents earthly joy and the natural pleasures of human cultivation (Psalm 104:15 — "wine that maketh glad the heart of man"). The Nazirite''s abstinence from the vine''s products is a total renunciation of natural satisfaction in favour of supernatural joy — God alone as sufficient delight', 'The vine was prohibited only because wine causes drunkenness', 'Grapes were scarce in the Sinai wilderness', 'The vine prohibition was a health regulation', 'a', 'Numbers 6:4 — "All the days of his separation shall he eat nothing that is made of the vine tree, from the kernels even to the husk." The totality of the prohibition (seeds to husk) signals complete separation from earthly gladness, reflecting Paul''s disposition in Philippians 4:11 — "I have learned, in whatsoever state I am, therewith to be content."'),
('Numbers', 6, 'adults', 6, 'How does the hair as the "crown of consecration" (6:7, nezer) connect the Nazirite to royal and priestly imagery?', 'Nezer means both "consecration" and "crown" — the same word used for the golden crown of the high priest (Exodus 29:6) and the royal crown (2 Samuel 1:10). The Nazirite''s uncut hair is their nezer, marking them as a royally consecrated person before God', 'The hair was symbolic only of personal hygiene', 'The word nezer has no connection to royal or priestly concepts', 'The hair was merely a visible sign for social identification', 'a', 'Numbers 6:7 — "Because the consecration (nezer) of his God is upon his head." Exodus 29:6 uses nezer for the high priest''s golden diadem. The Nazirite is thus a lay embodiment of the priest-king ideal, pointing forward to Christ''s supreme union of all three offices.'),
('Numbers', 6, 'adults', 7, 'What is the theological connection between the Nazirite vow and Christ''s statement "I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father''s kingdom" (Matthew 26:29)?', 'At the Last Supper, Jesus takes a Nazirite-like vow of abstinence from the vine until the Kingdom comes — His cross is the ultimate consecrated act, and His resurrection feast is the fulfilment of the completed Nazirite vow when all is presented before the Father', 'Jesus'' statement has no connection to the Nazirite tradition', 'The Last Supper vow was a personal preference with no typological meaning', 'Matthew 26:29 refers only to the abstinence of fasting', 'a', 'Matthew 26:29 — "I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father''s kingdom." Jesus'' voluntary abstinence from Gethsemane to resurrection parallels the Nazirite''s abstinence during the period of consecration, completed at the joyful peace offering.'),
('Numbers', 6, 'adults', 8, 'Why is it significant that both men and women could take the Nazirite vow, in the context of ancient Israelite society?', 'The Nazirite vow was one of the few religious acts in ancient Israel equally available to both sexes — any individual, regardless of gender, could take a vow of special consecration to God, demonstrating that intimate devotion to God is not restricted by social or gender roles', 'Women could only take the vow with their husband''s permission always', 'The vow was culturally assumed to be male-only', 'Women''s Nazirite vows had different requirements and fewer restrictions', 'a', 'Numbers 6:2 — "When either man or woman shall separate themselves to vow a vow of a Nazirite, to separate themselves unto the LORD." The explicit inclusion of women anticipates Galatians 3:28 — "There is neither male nor female: for ye are all one in Christ Jesus."');

-- ═══ Numbers Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 7, 'kids', 1, 'How many leaders brought offerings for the dedication of the tabernacle?', 'Twelve leaders, one from each tribe of Israel', 'Seven leaders from the most important tribes', 'Only three leaders: Judah, Reuben, and Ephraim', 'All the Levites together', 'a', 'Numbers 7:2 — "That the princes of Israel, heads of the house of their fathers, who were the princes of the tribes, and were over them that were numbered, offered."'),
('Numbers', 7, 'kids', 2, 'What did each of the twelve leaders bring that were the same as each other?', 'Each one brought exactly the same offering — a silver charger, a silver bowl, a golden spoon, burnt offerings, a sin offering, and peace offerings', 'Each one brought a different amount of silver', 'Each one brought a different number of animals', 'Each one brought whatever they could afford', 'a', 'Numbers 7:87 — "All the oxen for the burnt offering were twelve bullocks, the rams twelve, the lambs of the first year twelve, with their meat offering: and the kids of the goats for sin offering twelve."'),
('Numbers', 7, 'kids', 3, 'After Moses went into the tabernacle, what did he hear?', 'He heard the voice of God speaking to him from above the mercy seat between the two cherubims', 'He heard the singing of angels', 'He heard the sound of trumpets in the sky', 'He heard the priests praying loudly', 'a', 'Numbers 7:89 — "And when Moses was gone into the tabernacle of the congregation to speak with him, then he heard the voice of one speaking unto him from off the mercy seat that was upon the ark of testimony, from between the two cherubims: and he spake unto him."'),
-- Teens
('Numbers', 7, 'teens', 1, 'What was the very first offering on the first day, and who brought it?', 'Nahshon the son of Amminadab of the tribe of Judah brought the first offering — a silver charger of 130 shekels, a silver bowl of 70 shekels, a golden spoon of 10 shekels, and animals for burnt, sin, and peace offerings', 'Moses brought the first offering on behalf of all Israel', 'Aaron brought the first offering as high priest', 'The prince of Reuben brought the first offering', 'a', 'Numbers 7:12 — "And he that offered his offering the first day was Nahshon the son of Amminadab, of the tribe of Judah."'),
('Numbers', 7, 'teens', 2, 'What six wagons and twelve oxen were given to Moses and what were they used for?', 'Two princes gave one wagon between them, one ox each — the wagons were given to the Gershonites (two wagons) and Merarites (four wagons) for carrying tabernacle furnishings; the Kohathites received none because they carried holy things on their shoulders', 'The wagons were used to carry the ark of the covenant', 'All twelve wagons were given equally to all the Levites', 'The wagons were reserved for the elders of the people', 'a', 'Numbers 7:6-9 — "Moses took the wagons and the oxen, and gave them unto the Levites. Two wagons and four oxen he gave unto the sons of Gershon... And four wagons and eight oxen he gave unto the sons of Merari... But unto the sons of Kohath he gave none: because the service of the sanctuary belonging unto them was that they should bear upon their shoulders."'),
('Numbers', 7, 'teens', 3, 'What was the weight of the golden spoon offered by each prince, and what was it filled with?', 'Ten shekels of gold, full of incense', 'Twenty shekels of gold, full of oil', 'Five shekels of gold, full of frankincense', 'Fifteen shekels of gold, full of spices', 'a', 'Numbers 7:14 — "One spoon of ten shekels of gold, full of incense."'),
('Numbers', 7, 'teens', 4, 'Why does the text record each prince''s offering in full detail twelve times, rather than saying they all gave the same thing once?', 'Each tribe''s offering is individually honoured before God — the repetition declares that each leader and tribe stands before God with equal dignity and full recognition, none overshadowed by another', 'The scribe made a copying error', 'Different offerings were actually given but summarised identically', 'The repetition was a liturgical chant read aloud at the tabernacle', 'a', 'Numbers 7:10-83 — The Holy Spirit inspired the twelve-fold repetition to honour every tribe equally. Just as God knows every sparrow (Matthew 10:29), He fully acknowledges every act of devotion from every segment of His people.'),
('Numbers', 7, 'teens', 5, 'What was the total silver weight of all the chargers and bowls offered by the twelve princes?', 'Two thousand four hundred shekels of silver after the shekel of the sanctuary', 'One thousand shekels of silver', 'Three thousand shekels of silver', 'Twelve hundred shekels of gold', 'a', 'Numbers 7:85 — "Each charger of silver weighing an hundred and thirty shekels, each bowl seventy: all the silver vessels weighed two thousand and four hundred shekels, after the shekel of the sanctuary."'),
-- Adults
('Numbers', 7, 'adults', 1, 'What is the literary and theological significance of Numbers 7 being the longest chapter in the entire Bible?', 'God devotes more Scripture to the offerings of the twelve princes than to almost any other single event — communicating that detailed acts of worship and dedication are worthy of divine attention and honour; what men may find repetitive, God finds fully worthy of recording', 'The chapter is long because of scribal tradition, not divine purpose', 'The length was an accident of oral transmission', 'God''s attention is measured by the brevity of Scripture, not its length', 'a', 'Numbers 7 contains 89 verses, making it the longest chapter in the Bible. The Spirit''s choice to record each offering in full declares that God honours every individual act of consecration — a rebuke to any view that corporate worship makes individual devotion unnecessary.'),
('Numbers', 7, 'adults', 2, 'What does the identical nature of each prince''s offering communicate about God''s standard of worship?', 'God''s standard of approach is uniform and non-discriminatory — the prince of Judah (the leading tribe) and the prince of Benjamin (the smallest tribe) bring the same offering, declaring that all stand equally before God regardless of worldly rank or tribal prestige', 'The identical offerings showed a lack of creativity in worship', 'Richer tribes were expected to give more but chose to give the same', 'The uniformity was a practical arrangement for accounting', 'a', 'Numbers 7:12-83 — From the greatest tribe (Judah, 186,400 warriors) to the smallest (Benjamin, 35,400), every prince brings identical offerings. Romans 3:22 — "There is no difference: for all have sinned" — the equal standard of approach to God levels all human distinctions.'),
('Numbers', 7, 'adults', 3, 'Why did the Kohathites receive no wagons while the Gershonites and Merarites did?', 'The Kohathites carried the most holy things (ark, table, candlestick, altars) on their shoulders without wagons — a physical act of personal bearing that signified the intimate, unmediated responsibility of carrying God''s holiest objects. This was a privilege, not a burden', 'The Kohathites were too few to need wagons', 'Wagons were considered dishonourable in Israelite culture', 'The Kohathites had not yet been fully assigned their duties', 'a', 'Numbers 7:9 — "Unto the sons of Kohath he gave none: because the service of the sanctuary belonging unto them was that they should bear upon their shoulders." The shoulder-carrying of holy things typifies Christ''s personal bearing of humanity''s sin — Hebrews 1:3, "upholding all things by the word of his power."'),
('Numbers', 7, 'adults', 4, 'What does the sin offering (a male goat) included in each prince''s dedication package reveal about the nature of all approach to God?', 'Even joyful acts of dedication and consecration require atonement — no human act of worship is so pure that it needs no covering for sin. The sin offering embedded in the dedication gifts declares that access to God is always dependent on prior atonement', 'The sin offering was a traditional addition with no specific meaning', 'The sin offering was included for political correctness in tribal culture', 'Only the first offering required a sin offering', 'a', 'Numbers 7:16 — "One kid of the goats for a sin offering." Hebrews 9:22 — "Without shedding of blood is no remission." Every act of dedication in Numbers 7 is preceded by atonement — a permanent truth about approach to the holy God.'),
('Numbers', 7, 'adults', 5, 'How does the concluding verse (7:89) function as the theological climax of the entire chapter?', 'After twelve days of offerings and all the elaborate preparation, the purpose is finally revealed: Moses enters and hears God speak from between the cherubim. The entire chapter''s wealth and worship exists to establish the place where God and man can communicate — communion, not ceremony, is the ultimate goal', 'Verse 89 is an appendix unconnected to the chapter', 'The climax is the total count of offerings in verse 87-88', 'Moses entering the tabernacle was a routine event unrelated to the offerings', 'a', 'Numbers 7:89 — "He heard the voice of one speaking unto him from off the mercy seat... from between the two cherubims." All worship, offering, and consecration in Numbers 7 builds toward this: God speaking to man. The entire chapter is a theology of approach culminating in divine-human communion.'),
('Numbers', 7, 'adults', 6, 'What is the connection between the twelve princes'' offerings and the twelve stones on the high priest''s breastplate (Exodus 28)?', 'Both the twelve offerings and the twelve stones represent the twelve tribes brought before God — one by priestly mediation (the breastplate bears them on the priest''s heart), the other by personal devotion (each prince offers directly). Together they show the corporate and individual dimensions of Israel''s worship', 'The two items are unrelated ceremonies', 'The breastplate had no tribal significance', 'Only the Levitical tribes were represented on the breastplate', 'a', 'Exodus 28:21 — "The stones shall be with the names of the children of Israel, twelve, according to their names." Both Numbers 7 and Exodus 28 declare the same truth: every tribe is individually known and individually presented before God.'),
('Numbers', 7, 'adults', 7, 'How do the peace offerings in each prince''s dedication (two oxen, five rams, five he-goats, five lambs) reflect a theology of covenant fellowship?', 'Peace offerings (shelamim) were communion meals shared between the offerer, the priest, and God — the large number of peace offering animals in each prince''s gift signals that the tabernacle''s dedication is fundamentally about establishing covenant fellowship between God and His people, not merely ceremonial protocol', 'Peace offerings were simply the most common type of offering', 'The numbers were chosen for financial rather than theological reasons', 'Peace offerings had no communion dimension in Israel', 'a', 'Numbers 7:17 — "And for a sacrifice of peace offerings, two oxen, five rams, five he goats, five lambs of the first year." Leviticus 7:11-15 explains that peace offerings were shared feasts, typifying the fellowship meal of the Last Supper and the eschatological banquet of Revelation 19:9.'),
('Numbers', 7, 'adults', 8, 'What is the typological significance of the golden spoons filled with incense in relation to New Testament worship?', 'The golden spoon full of incense prefigures Revelation 5:8 where the elders hold golden bowls full of odours (incense) "which are the prayers of saints" — the incense of Numbers 7 typifies the prayers of God''s people offered before His throne as a fragrant act of devotion', 'The golden spoons were purely decorative', 'Incense in the OT has no connection to prayer', 'The spoons were used for measuring grain offerings only', 'a', 'Numbers 7:14 — "One spoon of ten shekels of gold, full of incense." Revelation 5:8 — "golden vials full of odours, which are the prayers of saints." The incense-filled spoons of Numbers 7 find their fulfilment in the heavenly altar where the prayers of all believers ascend as fragrant worship before God.');

-- ═══ Numbers Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 8, 'kids', 1, 'How many lamps did the golden lampstand have, and where were they to shine?', 'Seven lamps that gave light over against the lampstand', 'Five lamps on the sides and one on top', 'Twelve lamps, one for each tribe', 'Three lamps in a row', 'a', 'Numbers 8:2 — "When thou lightest the lamps, the seven lamps shall give light over against the candlestick."'),
('Numbers', 8, 'kids', 2, 'What did Moses and Aaron do to cleanse the Levites for their special service?', 'They sprinkled water of purifying on them, they shaved all their flesh, washed their clothes, and the children of Israel laid their hands on them', 'They made the Levites swim in the river three times', 'They anointed the Levites with oil only', 'They had the Levites fast for seven days', 'a', 'Numbers 8:7,10 — "And thus shalt thou do unto them, to cleanse them: Sprinkle water of purifying upon them, and let them shave all their flesh, and let them wash their clothes... And thou shalt bring the Levites before the LORD: and the children of Israel shall put their hands upon the Levites."'),
('Numbers', 8, 'kids', 3, 'After what age were the Levites to stop their heavy tabernacle work?', 'Fifty years old', 'Forty years old', 'Sixty years old', 'Seventy years old', 'a', 'Numbers 8:25 — "And from the age of fifty years they shall cease waiting upon the service thereof, and shall serve no more."'),
-- Teens
('Numbers', 8, 'teens', 1, 'What was the specific form of the golden lampstand, and who was its maker according to the text''s back reference?', 'Its pattern was beaten work of gold, made exactly as the LORD had shewed Moses — a reference to the design given in Exodus 25:31-40', 'It was made from seven separate pieces joined together', 'Solomon designed the lampstand later and it replaced Moses'' original', 'It was made of olive wood overlaid with gold', 'a', 'Numbers 8:4 — "And this work of the candlestick was of beaten gold, unto the shaft thereof, unto the flowers thereof, was beaten work: according unto the pattern which the LORD had shewed Moses, so he made the candlestick."'),
('Numbers', 8, 'teens', 2, 'What two offerings did Moses present for the Levites'' atonement and consecration?', 'A young bullock with a meat offering of flour mingled with oil for a burnt offering, and another young bullock for a sin offering', 'Two rams, one for sin and one for peace', 'A goat for sin and a lamb for burnt offering', 'Seven bulls and seven rams as a single combined offering', 'a', 'Numbers 8:8 — "Then let them take a young bullock with his meat offering, even fine flour mingled with oil, and another young bullock shalt thou take for a sin offering."'),
('Numbers', 8, 'teens', 3, 'What was the significance of the children of Israel laying their hands on the Levites during the consecration ceremony?', 'It was a formal act of presentation and transfer — Israel laid their hands on the Levites as a sign that the Levites were being given and offered to God on behalf of all Israel, as their representatives before the LORD', 'It was a blessing given by older brothers to younger', 'It transferred special spiritual gifts to the Levites', 'It was a ceremony of adoption making Levites full sons of Israel', 'a', 'Numbers 8:10 — "And thou shalt bring the Levites before the LORD: and the children of Israel shall put their hands upon the Levites." Verse 11 clarifies: Aaron offered them as "an offering of the children of Israel" — the laying on of hands identified the Levites as the whole congregation''s representative gift to God.'),
('Numbers', 8, 'teens', 4, 'At what age did Levites begin serving in the tabernacle according to Numbers 8, and how does this differ from Numbers 4?', 'Numbers 8 says from twenty-five years old, while Numbers 4 says from thirty — the five years from 25 to 30 may have been an apprenticeship or probationary period before full active service', 'Both chapters agree on thirty years', 'Numbers 8 says twenty years old', 'There is no age specification in Numbers 8', 'a', 'Numbers 8:24 — "This is it that belongeth unto the Levites: from twenty and five years old and upward they shall go in to wait upon the service of the tabernacle of the congregation." Numbers 4:3 specifies thirty. The five-year gap likely represents a period of supervised training.'),
('Numbers', 8, 'teens', 5, 'What role did retired Levites (over fifty) continue to play in the tabernacle service?', 'They were to minister with their brethren in the tabernacle of the congregation to keep the charge, but they were not to do the heavy work', 'They were completely released from all duties', 'They became teachers of the law to the younger Levites only', 'They supervised the offerings from outside the tabernacle', 'a', 'Numbers 8:26 — "But shall minister with their brethren in the tabernacle of the congregation, to keep the charge, and shall do no service." Retirement from heavy physical service did not mean retirement from the presence of God.'),
-- Adults
('Numbers', 8, 'adults', 1, 'What is the typological significance of the seven-branched lampstand (menorah) giving light in the context of John''s vision in Revelation 1?', 'The seven lamps of the tabernacle menorah find their NT counterpart in the seven golden candlesticks of Revelation 1:12-13, among which Christ walks as the great High Priest tending the light of the seven churches — the tabernacle lamp typifies the light of the gospel shining through the Church', 'The menorah of Numbers 8 and Revelation''s candlesticks are entirely unrelated', 'The seven lamps represent only the seven days of creation', 'John''s vision borrowed from Greek rather than Hebrew symbolism', 'a', 'Revelation 1:12-13 — "And I turned to see the voice that spake with me. And being turned, I saw seven golden candlesticks; And in the midst of the seven candlesticks one like unto the Son of man." The tabernacle menorah of Numbers 8 finds its fulfilment in the Church bearing Christ''s light.'),
('Numbers', 8, 'adults', 2, 'What is the theological meaning of the Levites being presented as a "wave offering" before the LORD (verses 11, 13, 15, 21)?', 'The wave offering (tenufah) was the gesture of presenting something to God and receiving it back for His service — the Levites were waved before God, given to Him, and then returned to serve in His name, just as all Christian ministry is first given to God before being received back as a gift of service', 'The wave offering was a purely ceremonial gesture with no symbolic meaning', 'The Levites were waved as a sign of dismissal from ordinary Israelite life', 'The wave offering applied only to food, not people', 'a', 'Numbers 8:11 — "And Aaron shall offer the Levites before the LORD for an offering of the children of Israel, that they may execute the service of the LORD." The wave offering principle — given to God, returned for God''s purposes — is the foundation of all Christian vocation (Romans 12:1).'),
('Numbers', 8, 'adults', 3, 'How does the Levites'' consecration ceremony (shaving, washing, hands laid on, offerings) parallel the ordination of priests, and what distinctions remain?', 'Both involved water purification and animal offerings, but priests were anointed with oil and clothed in specific garments (Leviticus 8) while Levites were not — the priests'' anointing signals unique mediatorial status while the Levites'' simpler rite marks a different though honoured form of God''s service', 'The two ceremonies were identical with no distinctions', 'Levites underwent a more elaborate ceremony than priests', 'Priests and Levites shared the same ordination without any distinction', 'a', 'Leviticus 8:12 — Aaron''s ordination included anointing oil poured on his head, absent from the Levites'' rite in Numbers 8. The different ceremonies reflect the different callings within one covenant community of service.'),
('Numbers', 8, 'adults', 4, 'What does the command to shave "all their flesh" as part of the Levites'' purification signify?', 'Total bodily shaving was a radical act of new beginning — stripping away every mark of the old life to present the whole person, every surface, as clean and fresh before God, symbolising complete consecration of the entire self rather than only the inward person', 'Shaving was a hygienic requirement for working near food', 'The shaving was a mark of mourning for the Levites'' separation from family life', 'Only the head was shaved; the text uses hyperbole', 'a', 'Numbers 8:7 — "Let them shave all their flesh, and let them wash their clothes, and so make themselves clean." The thoroughness of the rite declares total self-offering. Romans 12:1 — "present your bodies a living sacrifice, holy, acceptable unto God" — reflects this totality of consecration.'),
('Numbers', 8, 'adults', 5, 'How does the statement that the Levites were taken "instead of all the firstborn" (8:16-18) connect to the substitutionary principle that runs from Passover through the gospel?', 'The substitutionary chain is explicit: God took the Levites in place of the firstborns He claimed at Passover — establishing a pattern of substitutionary consecration that points forward to Christ, the firstborn of all creation, who stands in for all humanity before the Father', 'The substitution was a bureaucratic arrangement with no theological depth', 'The Levites were superior to firstborns and were an upgrade, not a substitute', 'The Passover and the Levitical system were unrelated redemptive structures', 'a', 'Numbers 8:17-18 — "For all the firstborn of the children of Israel are mine... and I have taken the Levites for all the firstborn." Colossians 1:15 — "He is the image of the invisible God, the firstborn of every creature." The Levites as substitute-firstborns typify Christ who is the supreme firstborn given as substitute for all.'),
('Numbers', 8, 'adults', 6, 'What is the significance of the specific phrase that the Levites were "wholly given unto him from among the children of Israel" (8:16)?', 'The Hebrew kullam nethunim ("wholly given") signals total dedication — not partial service, not conditional commitment. The Levites represent the ideal of complete self-giving to God''s service that the entire nation was called to but Israel corporately failed to achieve', 'The phrase simply records the administrative transfer of Levites to priestly oversight', 'Wholly given means they were given permanently without possibility of return', 'The phrase has no specific theological weight', 'a', 'Numbers 8:16 — "They are wholly given unto him from among the children of Israel." Deuteronomy 10:8-9 — The Lord is the Levites'' inheritance — "the LORD is his inheritance." Total giving is the foundation of total receiving; those wholly given to God are wholly sustained by God.'),
('Numbers', 8, 'adults', 7, 'How does the retirement provision for Levites at fifty (with continued light service) reflect God''s character as a considerate employer?', 'God''s design accommodates human physical limits graciously — rather than discarding aging servants, He transitions them to lighter supportive duties, honouring their years of faithfulness while protecting them from physical harm. This demonstrates that divine service is not merely utilitarian but relational', 'The retirement rule was Moses'' invention to manage personnel, not God''s initiative', 'God had no regard for the physical welfare of His servants', 'Retirement from service was a punishment for Levites who served poorly', 'a', 'Numbers 8:25-26 — "From the age of fifty years they shall cease waiting upon the service... But shall minister with their brethren in the tabernacle of the congregation, to keep the charge, and shall do no service." The provision echoes Isaiah 46:4 — "I have made, and I will bear; even I will carry, and will deliver you."'),
('Numbers', 8, 'adults', 8, 'What is the broader canonical significance of the lampstand''s light being maintained by priestly attention, in relation to Jesus'' teaching in Matthew 5:16?', 'The priests tending the lamps daily (trimming, replenishing oil) typifies the Church''s calling to maintain the light of the gospel through constant spiritual care — without deliberate tending, even the best lamp goes dark; "let your light so shine" requires intentional, ongoing effort', 'Jesus'' teaching on light is unrelated to the tabernacle lampstand', 'The lampstand maintained itself supernaturally without human attention', 'Matthew 5:16 refers to personal morality with no connection to corporate worship', 'a', 'Matthew 5:16 — "Let your light so shine before men, that they may see your good works, and glorify your Father which is in heaven." The Levitical priests tended the menorah daily — their faithful care is the model for the Church''s ongoing responsibility to maintain the light of Christ in the world.');

-- ═══ Numbers Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 9, 'kids', 1, 'What important feast did God tell Moses the children of Israel should keep in the wilderness?', 'The Passover', 'The Feast of Tabernacles', 'The Feast of Firstfruits', 'The Day of Atonement', 'a', 'Numbers 9:2 — "Let the children of Israel also keep the passover at his appointed season."'),
('Numbers', 9, 'kids', 2, 'What covered the tabernacle by day to guide Israel in the wilderness?', 'A cloud covered the tabernacle by day', 'A pillar of smoke', 'A rainbow in the sky', 'An angel with a bright sword', 'a', 'Numbers 9:15-16 — "And on the day that the tabernacle was reared up the cloud covered the tabernacle... and at even there was upon the tabernacle as it were the appearance of fire, until the morning."'),
('Numbers', 9, 'kids', 3, 'How did Israel know when to move camp and when to stay in place?', 'When the cloud lifted from the tabernacle they journeyed, and when it stayed they camped and rested', 'Moses gave a signal with a trumpet', 'A star appeared in the direction they should go', 'The oldest elder decided when to move', 'a', 'Numbers 9:17 — "And when the cloud was taken up from the tabernacle, then after that the children of Israel journeyed: and in the place where the cloud abode, there the children of Israel pitched their tents."'),
-- Teens
('Numbers', 9, 'teens', 1, 'What problem arose when some men were unclean from a dead body and could not keep the Passover at its appointed time?', 'They came to Moses and Aaron distressed, asking why they should be kept from offering the LORD''s offering at the appointed season among the children of Israel', 'They kept the Passover anyway and were punished', 'They were told to wait until the next year''s Passover', 'They were exiled from the camp permanently', 'a', 'Numbers 9:7 — "And those men said unto him, We are defiled by the dead body of a man: wherefore are we kept back, that we may not offer an offering of the LORD in his appointed season among the children of Israel?"'),
('Numbers', 9, 'teens', 2, 'What was God''s solution for those who were unclean or on a journey when the first Passover was observed?', 'They were to keep a second Passover one month later, on the fourteenth day of the second month', 'They were permanently excused from keeping the Passover', 'They had to observe the Passover the following year instead', 'They could observe the Passover at any time convenient to them', 'a', 'Numbers 9:11 — "The fourteenth day of the second month at even they shall keep it, and eat it with unleavened bread and bitter herbs."'),
('Numbers', 9, 'teens', 3, 'What was the penalty for a clean person who wilfully refused to keep the Passover at its appointed time?', 'That soul shall be cut off from his people, having borne his sin by failing to bring the LORD''s offering at the appointed season', 'He was required to give extra offerings as compensation', 'He was put out of the camp for seven days only', 'He was fined the equivalent of the Passover lamb''s value', 'a', 'Numbers 9:13 — "But the man that is clean, and is not in a journey, and forbeareth to keep the passover, even the same soul shall be cut off from among his people."'),
('Numbers', 9, 'teens', 4, 'What provision was made for strangers (foreigners) living among Israel who wanted to keep the Passover?', 'One ordinance was given for both stranger and native — the stranger shall keep the Passover according to the same statute and manner as the Israelites', 'Strangers were not permitted to observe the Passover at all', 'Strangers observed a separate, simpler version of the Passover', 'Strangers could only watch but not participate', 'a', 'Numbers 9:14 — "And if a stranger shall sojourn among you, and will keep the passover unto the LORD; according to the ordinance of the passover, and according to the manner thereof, so shall he do."'),
('Numbers', 9, 'teens', 5, 'How is the responsiveness of Israel to the cloud described, emphasising their obedience?', 'Whether the cloud stayed two days, a month, or a year, Israel abode in camp and did not journey; when it lifted they journeyed — they kept the LORD''s charge at His commandment', 'Israel sometimes went ahead of the cloud when they were eager to reach Canaan', 'The cloud only appeared twice during the wilderness journey', 'Israel voted on whether to follow the cloud each time it moved', 'a', 'Numbers 9:22-23 — "Whether it were two days, or a month, or a year, that the cloud tarried upon the tabernacle, remaining thereon, the children of Israel abode in their tents, and journeyed not... they kept the charge of the LORD."'),
-- Adults
('Numbers', 9, 'adults', 1, 'What is theologically significant about the second Passover provision, making Numbers 9 the first recorded instance of a "make-up" observance?', 'God''s gracious provision for a delayed Passover demonstrates that He accommodates the complexities of human circumstance without compromising the ordinance''s importance — the feast must be kept, but mercy finds a way for those genuinely hindered, revealing that God is both holy (the feast cannot be simply skipped) and gracious (a path of restoration is provided)', 'The second Passover shows that God was indifferent to the timing of worship', 'The provision was a one-time exception never to be repeated', 'Numbers 9 establishes that all feast dates are flexible', 'a', 'Numbers 9:10-11 — "Speak unto the children of Israel, saying, If any man of you or of your posterity shall be unclean by reason of a dead body, or be in a journey afar off, yet he shall keep the passover unto the LORD. The fourteenth day of the second month at even they shall keep it."'),
('Numbers', 9, 'adults', 2, 'How does the cloud and fire guiding Israel typologically anticipate the Holy Spirit''s guidance of the New Testament Church?', 'The cloud by day and fire by night represents God''s tangible, observable guidance — the Spirit''s guidance in the NT is equally real though not visible, leading believers into all truth (John 16:13) and directing the Church''s mission (Acts 16:6-7) just as the cloud directed Israel''s march', 'The cloud and fire were purely meteorological phenomena with no spiritual significance', 'The Holy Spirit''s guidance is completely different in kind from the cloud-pillar', 'The cloud typifies only the Second Coming, not present guidance', 'a', 'John 16:13 — "Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak." The cloud''s function of divine guidance is fulfilled in the Spirit''s continuous leading of the Church.'),
('Numbers', 9, 'adults', 3, 'What does the phrase "according to the commandment of the LORD they rested, and according to the commandment of the LORD they journeyed" (9:23) reveal about Israel''s ideal spiritual posture?', 'Perfect obedience means neither moving when God says rest nor resting when God says move — the believer''s life is defined not by personal preference or momentum but by undivided attentiveness and responsiveness to God''s direction', 'Israel''s obedience was conditional on the convenience of the journey', 'The verse describes geographic direction only, not spiritual principle', 'Israel kept the LORD''s charge only when the journey suited them', 'a', 'Numbers 9:23 — "They kept the charge of the LORD, at the commandment of the LORD by the hand of Moses." Psalm 119:105 — "Thy word is a lamp unto my feet, and a light unto my path" — expresses the same principle of divine direction guiding every step.'),
('Numbers', 9, 'adults', 4, 'What is the theological significance of including strangers in the same Passover ordinance as native Israelites (verse 14)?', 'It foreshadows the breaking down of ethnic divisions in the people of God — the stranger who aligns with Israel''s covenant community participates equally in the covenant meal, typifying Ephesians 2:12-13 where Gentiles who were strangers from the covenants are brought near by Christ''s blood', 'The provision for strangers was a pragmatic social policy only', 'Strangers were only included to increase the size of Israel''s army', 'The inclusion of strangers was exceptional and later revoked', 'a', 'Numbers 9:14 — "One ordinance shall be both for the stranger, and for him that was born in the land." Ephesians 2:12-13 — "Strangers from the covenants of promise... but now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ."'),
('Numbers', 9, 'adults', 5, 'How does the second Passover''s identity with the first (same rules: lamb, unleavened bread, bitter herbs, no bones broken) teach about the unchanging nature of the gospel?', 'God does not alter the substance of the gospel for human convenience — the essentials of the Passover (atonement, bitter experience of sin, unleavened purity, the unbroken body) remain constant whether celebrated in the first or second month, typifying that Christ''s sacrifice is eternally the same gospel', 'The identical rules were purely administrative uniformity', 'The second Passover was a lesser observance with simplified requirements', 'The rules changed slightly to accommodate those who had been unclean', 'a', 'Numbers 9:12 — "They shall leave none of it unto the morning, nor break any bone of it: according to all the ordinances of the passover they shall keep it." John 19:36 — "These things were done, that the scripture should be fulfilled, A bone of him shall not be broken." The unchanging Passover ordinance is precisely fulfilled in Christ.'),
('Numbers', 9, 'adults', 6, 'What is the theological weight of cutting someone off from Israel for wilfully neglecting the Passover (9:13)?', 'The Passover was not an optional religious tradition but the constitutive act of Israel''s identity as God''s redeemed people — to refuse the Passover was to repudiate the redemption it commemorated and to sever oneself from the covenant community. Hebrews 10:29 warns of a similar spiritual consequence for despising the blood of Christ', 'Being cut off was merely social excommunication with no spiritual meaning', 'The penalty was a deterrent rather than a spiritual principle', 'God would restore such a person automatically after a period of time', 'a', 'Hebrews 10:29 — "Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant... an unholy thing?" Refusing the Passover (Numbers 9:13) and despising Christ''s atoning work both carry the weight of covenant self-exclusion.'),
('Numbers', 9, 'adults', 7, 'What does the variability of the cloud''s resting period (two days to a year, 9:22) teach about submission to unpredictable divine timing?', 'God''s timing is not subject to human schedules — the believer must be equally willing to "wait" for extended periods or "march" at a moment''s notice, cultivating a detachment from personal plans that keeps them perpetually available for divine direction. This is the heart of Proverbs 3:5-6', 'The variable timing was a test of endurance rather than a spiritual principle', 'Israel should have anticipated the cloud''s movements and planned around them', 'God''s timing was predictable once they learned to read the cloud''s patterns', 'a', 'Numbers 9:22 — "Whether it were two days, or a month, or a year... the children of Israel abode in their tents, and journeyed not." Proverbs 3:5-6 — "Trust in the LORD with all thine heart... In all thy ways acknowledge him, and he shall direct thy paths."'),
('Numbers', 9, 'adults', 8, 'How does the Passover''s timing "in the first month, on the fourteenth day" connect to the Passion narrative of the Gospels, making Numbers 9 typologically relevant to Christ''s crucifixion?', 'The Gospels record Christ crucified on the fourteenth of Nisan (the first month), precisely when the Passover lamb was slain — John 19:14 places the crucifixion at the "preparation of the Passover." Numbers 9 reinforces the Passover''s perpetual, unalterable timing, which the Cross fulfils exactly', 'The Passover date was changed in the NT to accommodate the resurrection', 'Christ was crucified on the fifteenth of Nisan, after the Passover', 'The connection between Numbers 9 and the Passion is a later theological invention', 'a', 'Numbers 9:3 — "In the fourteenth day of this month, at even, ye shall keep it in his appointed season." John 19:14 — "And it was the preparation of the passover... he saith unto the Jews, Behold your King." The divine appointment of the Passover''s date in Numbers 9 is the same appointment kept by the Lamb of God on Calvary.');

-- ═══ Numbers Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 10, 'kids', 1, 'What did God tell Moses to make two of, for calling the people of Israel together?', 'Two silver trumpets', 'Two golden horns', 'Two wooden rams'' horns', 'Two bronze bells', 'a', 'Numbers 10:2 — "Make thee two trumpets of silver; of a whole piece shalt thou make them: that thou mayest use them for the calling of the assembly, and for the journeying of the camps."'),
('Numbers', 10, 'kids', 2, 'Where did Israel leave from on their journey, and how long had they been camped there?', 'They left the wilderness of Sinai, where they had camped for about one year and one month', 'They left Egypt directly into Canaan', 'They left Goshen after forty years', 'They left the Red Sea after two months', 'a', 'Numbers 10:11-12 — "And it came to pass on the twentieth day of the second month, in the second year, that the cloud was taken up from off the tabernacle of the testimony. And the children of Israel took their journeys out of the wilderness of Sinai."'),
('Numbers', 10, 'kids', 3, 'What did Moses say when the ark set forward on the journey?', '"Rise up, LORD, and let thine enemies be scattered; and let them that hate thee flee before thee."', '"Go before us O God and make us strong."', '"Lead us safely into the promised land."', '"Let all nations fear the LORD our God."', 'a', 'Numbers 10:35 — "And it came to pass, when the ark set forward, that Moses said, Rise up, LORD, and let thine enemies be scattered; and let them that hate thee flee before thee."'),
-- Teens
('Numbers', 10, 'teens', 1, 'What were the different signals the silver trumpets gave, and what did each signal mean?', 'Blowing both trumpets assembled the whole congregation; blowing one called the princes; an alarm (tekiah) started the journey of the eastern camp; a second alarm started the southern camp', 'One blast meant stop, two blasts meant go', 'The trumpets were only blown on feast days and new moons', 'Only the alarm was used; different notes had no distinct meanings', 'a', 'Numbers 10:3-6 — One blast: princes assemble. Two blasts: whole congregation. Alarm (first): east camp moves. Second alarm: south camp moves. Numbers 10:7 — for the general assembly, trumpets are blown, not sounded as alarms.'),
('Numbers', 10, 'teens', 2, 'Who alone was authorised to blow the silver trumpets?', 'Aaron''s sons the priests — an everlasting ordinance throughout all generations', 'The tribal leaders of each camp', 'Any Levite designated by Moses', 'The heads of the twelve families', 'a', 'Numbers 10:8 — "And the sons of Aaron, the priests, shall blow with the trumpets; and they shall be to you for an ordinance for ever throughout your generations."'),
('Numbers', 10, 'teens', 3, 'Whom did Moses invite to travel with Israel as a guide through the wilderness, and what did he promise him?', 'His father-in-law Hobab the Midianite — Moses offered that Hobab come with them and they would do him good because the LORD had promised good to Israel', 'Jethro his father-in-law, who had already agreed to come', 'The king of Amalek, offering peace and land', 'Caleb the son of Jephunneh, asking him to scout the way ahead', 'a', 'Numbers 10:29,31 — "And Moses said unto Hobab, the son of Raguel the Midianite, Moses'' father in law, We are journeying unto the place of which the LORD said, I will give it you... come thou with us, and we will do thee good."'),
('Numbers', 10, 'teens', 4, 'In what order did the tribes march when Israel set out from Sinai?', 'The standard of the camp of Judah first, then Gershonites and Merarites with the tabernacle, then Reuben''s camp, then the Kohathites with the sanctuary, then Ephraim''s camp, then Dan''s camp as the rearguard', 'Dan''s camp led, followed by Reuben, then Judah last', 'All twelve tribes marched simultaneously in four equal groups', 'Moses led on foot at the very front ahead of all the tribes', 'a', 'Numbers 10:14-25 — The standard march order: Judah (v.14), then the tabernacle frames carried by Gershon and Merari (v.17), then Reuben (v.18), then Kohath with holy things (v.21), then Ephraim (v.22), then Dan bringing up the rear (v.25).'),
('Numbers', 10, 'teens', 5, 'What did Moses say when the ark rested after a journey, and what does it express about the desire for God''s presence to rest with His people?', '"Return, O LORD, unto the many thousands of Israel" — expressing the longing for God to dwell continuously among His vast redeemed people', '"The LORD has led us well; let us give thanks."', '"Rest, O ark, until we journey again at dawn."', '"Praise the LORD for bringing us to this place of safety."', 'a', 'Numbers 10:36 — "And when it rested, he said, Return, O LORD, unto the many thousands of Israel." The prayer expresses the deepest desire of Israel: not merely to arrive at a destination but to have God''s presence rest upon them.'),
-- Adults
('Numbers', 10, 'adults', 1, 'What is the theological significance of the silver trumpets being "of a whole piece" (taqshit, hammered work) rather than assembled from parts?', 'Like the menorah (Exodus 25:36), the trumpets are beaten from a single piece of silver — symbolising undivided wholeness and purity of divine communication. God''s call is not a composite of human elements but proceeds from His own integrated holiness', 'Hammered work was simply the available technology', 'The whole-piece construction prevented the trumpets from falling apart during travel', 'The silver was worked in pieces but the text uses metaphorical language', 'a', 'Numbers 10:2 — "Of a whole piece shalt thou make them." The Hebrew miqs''shah (hammered from one piece) is the same word used for the menorah''s construction (Exodus 25:36), associating the trumpets'' sound with the lamp''s light — both proceeding from God''s undivided, uncompromised holiness.'),
('Numbers', 10, 'adults', 2, 'How does the promise that God will "remember" Israel when the trumpets are blown before Him in battle connect to the covenant theology of Exodus 2?', 'The trumpets are a covenant-invocation mechanism — blowing them before God in battle calls upon His covenant remembrance (zakar), the same active remembrance that moved God to deliver Israel from Egypt (Exodus 2:24). The trumpets literally call God''s covenant memory into action', 'The trumpets were purely practical military signals with no theological dimension', 'God''s remembrance in Numbers 10 is a different concept from Exodus 2', 'The promise was conditional on Israel first winning a battle', 'a', 'Numbers 10:9 — "And if ye go to war in the land... then ye shall blow an alarm with the trumpets; and ye shall be remembered before the LORD your God." Exodus 2:24 — "And God remembered his covenant." The same zakar/remembered language connects both passages in one theology of covenant invocation.'),
('Numbers', 10, 'adults', 3, 'What does Moses'' invitation to Hobab reveal about the relationship between divine guidance (the cloud) and human wisdom in God''s economy?', 'Even with the cloud as a perfect divine GPS, Moses valued Hobab''s wilderness expertise — God''s supernatural guidance does not eliminate the legitimate use of human knowledge and skill. Divine sovereignty and human instrumentality cooperate in God''s purposes', 'The invitation to Hobab contradicts the cloud''s sufficiency', 'Moses was expressing a lack of faith in the cloud by seeking a human guide', 'God approved of Hobab''s guidance as superior to the cloud''s direction', 'a', 'Numbers 10:31 — "Leave us not, I pray thee; forasmuch as thou knowest how we are to encamp in the wilderness, and thou mayest be to us instead of eyes." The cloud guaranteed divine direction; Hobab''s local knowledge served the practical details of camp life — the two are complementary, not competing.'),
('Numbers', 10, 'adults', 4, 'How does the departure from Sinai (the "mountain of God," 10:33) mark a theological transition in the book of Numbers?', 'Sinai was the mountain of the Law''s giving and the tabernacle''s construction — the pinnacle of divine revelation in the wilderness. Departure from Sinai is departure from the place of supreme covenant formation, launching Israel into the faith-walk of following God''s presence rather than dwelling at the site of His revelation', 'The departure from Sinai was purely geographical with no theological significance', 'Sinai remained the centre of Israelite worship throughout the wilderness period', 'The departure marked the end of God''s covenant with Israel', 'a', 'Numbers 10:33 — "They departed from the mount of the LORD three days'' journey." Exodus 19:1-2 established Sinai as where God met Israel. Departure launches the lived-out obedience that the Sinai covenant demanded — the test of whether covenant knowledge would produce covenant faithfulness.'),
('Numbers', 10, 'adults', 5, 'What is the typological significance of the "ark of the covenant of the LORD going before them to search out a resting place" (verse 33)?', 'The ark going before Israel to search out their rest typifies Christ who goes before His people as the pioneer and perfecter of faith (Hebrews 12:2), preparing a place for them (John 14:2-3) — the ark''s movement from Sinai toward Canaan''s rest is a type of Christ''s ascension to prepare our heavenly rest', 'The ark''s movement was purely practical for navigational purposes', 'The resting place referred only to Israel''s nightly camping ground', 'The ark''s position was determined by the Kohathites, not divine purpose', 'a', 'Numbers 10:33 — "The ark of the covenant of the LORD went before them in the three days'' journey, to search out a resting place for them." Hebrews 4:8-9 — "For if Jesus had given them rest... There remaineth therefore a rest to the people of God." The ark searching out rest anticipates Christ preparing our eternal rest.'),
('Numbers', 10, 'adults', 6, 'How do Moses'' war-cry and rest-prayer (10:35-36) function as a theology of holy war, and how are they echoed in the Psalms?', 'Moses'' words became the template for Israel''s liturgical understanding of battle as God''s action — Psalm 68:1 directly quotes verse 35 ("Let God arise, let his enemies be scattered"), showing that Numbers 10:35-36 became a permanent part of Israel''s warfare liturgy', 'Moses'' words were spontaneous and not intended as liturgical formulas', 'The war-cry and rest-prayer were local customs, not theological formulas', 'Psalm 68 is unrelated to Moses'' words in Numbers 10', 'a', 'Psalm 68:1 — "Let God arise, let his enemies be scattered: let them also that hate him flee before him." This is a direct liturgical use of Numbers 10:35, confirming that Moses'' ark prayers became the foundation for Israel''s holy war theology in the Psalter.'),
('Numbers', 10, 'adults', 7, 'What is the significance of the cloud resting "in the wilderness of Paran" after Israel''s departure from Sinai?', 'Paran is the wilderness of waiting — it is where Ishmael dwelt (Genesis 21:21) and where the spies were later sent from (Numbers 13:3). The cloud''s first resting place after Sinai is the threshold of the land''s testing, establishing that the faith formed at Sinai will be tried in the wilderness before Canaan is entered', 'Paran was simply the nearest geographical location and has no significance', 'The cloud''s resting in Paran was a mistake that Moses corrected', 'Paran was Israel''s final destination rather than a waystation', 'a', 'Numbers 10:12 — "The children of Israel took their journeys out of the wilderness of Sinai; and the cloud rested in the wilderness of Paran." From Paran the spies are sent (Numbers 13:3,26), making it the wilderness of testing where Sinai-formed faith encounters the challenge of Canaan''s giants.'),
('Numbers', 10, 'adults', 8, 'How does the inclusion of the trumpet ordinance for feast days and new moons (verse 10) connect the trumpets to the entire liturgical calendar and not merely to military use?', 'The trumpets are not solely battle instruments but are woven into the full rhythm of Israel''s sacred time — sounding at every sacrifice, feast, and new moon as a perpetual reminder that all of Israel''s time belongs to God, anticipating Revelation 8-11 where seven trumpets structure the consummation of God''s redemptive calendar', 'The feast-day trumpets were a minor addition with no theological connection to the military use', 'The liturgical trumpets were entirely different instruments from the battle trumpets', 'New moon trumpet blasts were a human invention not commanded by God', 'a', 'Numbers 10:10 — "Also in the day of your gladness, and in your solemn days, and in the beginnings of your months, ye shall blow with the trumpets over your burnt offerings... and they shall be to you for a memorial before your God." Revelation 8:2 — "And I saw the seven angels which stood before God; and to them were given seven trumpets." The trumpet liturgy of Numbers 10 becomes the cosmic trumpet sequence of Revelation''s final redemptive acts.');
